SELECT COUNT(1) AS QUANTIDADE FROM LATTES_P_EVENTO PE JOIN LATTES_EVENTO E ON E.PK = PE.FK_EVENTO JOIN SERVIDOR S ON S.PK_SIAPE = PE.FK_SIAPE WHERE LOWER(PE.TIPO) LIKE LOWER('%apresentacao oral%') AND LOWER(S.GENERO) = LOWER('masculino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('apa') AND E.ANO = 2021 AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%educacao fisica%'